// frontend/src/pages/Dashboard.js
import { useEffect, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";
import { Link } from "react-router-dom";

const fmtVND = (v) => (v == null ? "—" : v.toLocaleString("vi-VN") + " ₫");
const fmtD = (d) => {
    if (!d) return "-";
    const x = new Date(d);
    if (isNaN(x)) return d;
    return `${x.getDate().toString().padStart(2, "0")}/${(x.getMonth() + 1)
        .toString()
        .padStart(2, "0")}/${x.getFullYear()}`;
};
const roleMatch = (u, roles = []) => {
    const bag = new Set();
    const add = (x) => {
        if (!x) return;
        if (Array.isArray(x)) return x.forEach(add);
        if (typeof x === "string") return bag.add(x.toUpperCase());
        if (typeof x === "object") {
            ["role", "name", "authority", "code"].forEach(
                (k) => x[k] && bag.add(String(x[k]).toUpperCase())
            );
            ["roles", "authorities"].forEach((k) => add(x[k]));
        }
    };
    add(u?.role);
    add(u?.roles);
    add(u?.authorities);
    return roles.some((r) => bag.has(r));
};

export default function Dashboard() {
    const { user } = useAuth();
    const [stats, setStats] = useState({
        customers: 0,
        contracts: 0,
        paid: 0,
        remain: 0,
    });
    const [recentContracts, setRecentContracts] = useState([]);
    const [upcomingEvents, setUpcomingEvents] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        loadDashboard();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    async function loadDashboard() {
        setLoading(true);
        try {
            // 1️⃣ Tổng khách hàng
            const custRes = await api.get("/api/customers", {
                params: { page: 0, size: 1 },
            });
            const totalCust =
                custRes.data?.totalElements ??
                (Array.isArray(custRes.data) ? custRes.data.length : 0);

            // 2️⃣ Hợp đồng
            const contractRes = await api.get("/api/contracts", {
                params: { page: 0, size: 5, sort: "id,desc" },
            });
            const list = Array.isArray(contractRes.data)
                ? contractRes.data
                : contractRes.data?.content || [];
            const totalContracts =
                contractRes.data?.totalElements ??
                (Array.isArray(contractRes.data) ? contractRes.data.length : 0);
            const sumPaid = list.reduce(
                (s, x) => s + Number(x.paidAmount || 0),
                0
            );
            const sumTotal = list.reduce(
                (s, x) => s + Number(x.totalAmount || 0),
                0
            );
            const remain = Math.max(0, sumTotal - sumPaid);
            setStats({
                customers: totalCust,
                contracts: totalContracts,
                paid: sumPaid,
                remain,
            });

            // 3️⃣ Lấy danh sách hợp đồng gần đây
            setRecentContracts(
                list.map((x) => ({
                    id: x.id,
                    code: x.contractCode,
                    title: x.title,
                    customer: x.customerName,
                    total: x.totalAmount,
                    signedDate: x.signedDate,
                    status: x.status,
                }))
            );

            // 4️⃣ Sự kiện sắp tới
            const isAdmin = roleMatch(user, ["ADMIN"]);
            const url = isAdmin ? "/api/events/admin" : "/api/events/me";
            const eventRes = await api.get(url, {
                params: {
                    from: new Date().toISOString().slice(0, 10),
                    size: 5,
                    sort: "startAt,asc",
                },
            });
            const eList = Array.isArray(eventRes.data)
                ? eventRes.data
                : eventRes.data?.content || [];
            setUpcomingEvents(
                eList.map((e) => ({
                    id: e.id,
                    title: e.title,
                    type: e.type,
                    startAt: e.startAt,
                    customer: e.customerName,
                    status: e.status,
                }))
            );
        } catch (err) {
            console.error("Dashboard load error:", err);
        }
        setLoading(false);
    }

    return (
        <div className="space-y-6">
            {/* ==== Stats row ==== */}
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">
                {[
                    { label: "Khách hàng", val: stats.customers, color: "indigo" },
                    { label: "Hợp đồng", val: stats.contracts, color: "emerald" },
                    { label: "Đã thu", val: fmtVND(stats.paid), color: "amber" },
                    { label: "Còn lại", val: fmtVND(stats.remain), color: "rose" },
                ].map((m, i) => (
                    <div
                        key={i}
                        className={`p-5 rounded-2xl bg-white shadow border border-${m.color}-100`}
                    >
                        <div className="text-sm text-slate-500">{m.label}</div>
                        <div className="mt-1 text-2xl font-bold">{m.val}</div>
                    </div>
                ))}
            </div>

            {/* ==== Contracts & Events ==== */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2 p-5 rounded-2xl bg-white shadow border border-indigo-100">
                    <div className="flex items-center justify-between mb-3">
                        <div className="font-semibold">Hợp đồng gần đây</div>
                        <Link
                            to="/contracts"
                            className="text-sm text-indigo-600 hover:underline"
                        >
                            Xem tất cả
                        </Link>
                    </div>
                    {loading ? (
                        <div className="text-slate-500 text-sm">Đang tải...</div>
                    ) : recentContracts.length === 0 ? (
                        <div className="text-slate-500 text-sm">
                            Sẽ hiển thị khi bạn thêm dữ liệu.
                        </div>
                    ) : (
                        <table className="min-w-full text-sm">
                            <thead className="bg-indigo-50">
                            <tr>
                                <th className="px-3 py-2 text-left">Mã</th>
                                <th className="px-3 py-2 text-left">Khách hàng</th>
                                <th className="px-3 py-2 text-left">Ngày ký</th>
                                <th className="px-3 py-2 text-left">Giá trị</th>
                                <th className="px-3 py-2 text-left">Trạng thái</th>
                            </tr>
                            </thead>
                            <tbody className="divide-y">
                            {recentContracts.map((c) => (
                                <tr key={c.id} className="hover:bg-indigo-50/40">
                                    <td className="px-3 py-2 font-medium text-indigo-700">
                                        {c.code}
                                    </td>
                                    <td className="px-3 py-2">{c.customer || "-"}</td>
                                    <td className="px-3 py-2">{fmtD(c.signedDate)}</td>
                                    <td className="px-3 py-2">{fmtVND(c.total)}</td>
                                    <td className="px-3 py-2">{c.status || "-"}</td>
                                </tr>
                            ))}
                            </tbody>
                        </table>
                    )}
                </div>

                <div className="p-5 rounded-2xl bg-white shadow border border-indigo-100">
                    <div className="flex items-center justify-between mb-3">
                        <div className="font-semibold">Sự kiện sắp tới</div>
                        <Link
                            to="/events"
                            className="text-sm text-indigo-600 hover:underline"
                        >
                            Xem tất cả
                        </Link>
                    </div>
                    {loading ? (
                        <div className="text-slate-500 text-sm">Đang tải...</div>
                    ) : upcomingEvents.length === 0 ? (
                        <div className="text-slate-500 text-sm">
                            Sẽ hiển thị khi bạn thêm dữ liệu.
                        </div>
                    ) : (
                        <ul className="space-y-2">
                            {upcomingEvents.map((e) => (
                                <li
                                    key={e.id}
                                    className="border border-indigo-50 rounded-xl p-3 hover:bg-indigo-50/50"
                                >
                                    <div className="text-sm font-medium text-indigo-700">
                                        {e.title}
                                    </div>
                                    <div className="text-xs text-slate-500">
                                        {fmtD(e.startAt)} • {e.customer || "—"}
                                    </div>
                                </li>
                            ))}
                        </ul>
                    )}
                </div>
            </div>
        </div>
    );
}
